import osimport matplotlib.pyplot as pltimport numpy as npRESULTS_DIR = "eval_results"MODEL_TAGS = ["qwen", "qwen-sft-bot", "qwen-sft-selfplay", "qwen-grpo"]INCLUDE_BOT_AVG = TrueMODEL_DISPLAY_NAMES = {    "qwen": "Qwen",    "qwen-sft-bot": "Qwen-SFT-Bot",    "qwen-sft-selfplay": "Qwen-SFT-SelfPlay",    "qwen-grpo": "Qwen-GRPO",    "bot-avg": "Bot Avg",}MODEL_COLORS = {    "qwen": "#666666",    "qwen-sft-bot": "#FFB347",    "qwen-sft-selfplay": "#FF8844",    "qwen-grpo": "#FF4444",    "bot-avg": "#2A7FFF",}MODEL_HATCHES = {    "qwen": "",                 # 无填充    "qwen-sft-bot": "//",       # 斜线    "qwen-sft-selfplay": "\\\\",# 反斜线    "qwen-grpo": "xx",          # 交叉线    "bot-avg": "..",            # 点状}LLM_PLAYER_ID = 0BOT_PLAYER_IDS = [1, 2, 3]def configure_matplotlib():    plt.rcParams["font.family"] = "DejaVu Sans"    plt.rcParams["axes.unicode_minus"] = False    plt.rcParams["figure.dpi"] = 150def load_saved_summary(model_tag):    path = os.path.join(RESULTS_DIR, f"{model_tag}_summary.npz")    if not os.path.exists(path):        return None    data = np.load(path, allow_pickle=True)    return {        "model_tag": model_tag,        "avg_stats": {            "hu_count": np.array(data["hu_count"], dtype=float),            "hu_fan_ge_1": np.array(data["hu_fan_ge_1"], dtype=float),            "dianpao_count": np.array(data["dianpao_count"], dtype=float),            "total_fan": np.array(data["total_fan"], dtype=float),        },        "avg_final_balances": np.array(data["avg_final_balances"], dtype=float),        "initial_balance": float(data.get("initial_balance", 10000)),        "num_episodes": int(data["num_episodes"]),    }def build_metric_data(model_tags):    summaries = []    missing_tags = []    for tag in model_tags:        summary = load_saved_summary(tag)        if summary is None:            missing_tags.append(tag)        else:            summaries.append(summary)    if missing_tags:        raise FileNotFoundError(f"Missing result files: {', '.join(missing_tags)}")    labels = [MODEL_DISPLAY_NAMES.get(s["model_tag"], s["model_tag"]) for s in summaries]    colors = [MODEL_COLORS.get(s["model_tag"], "#333333") for s in summaries]    hatches = [MODEL_HATCHES.get(s["model_tag"], "") for s in summaries]    hu_rates = []    fan_ge_2_counts = []    dianpao_rates = []    total_fans = []    final_balances = []    net_incomes = []    for summary in summaries:        num_episodes = summary["num_episodes"]        initial_balance = summary["initial_balance"]        hu_count = float(summary["avg_stats"]["hu_count"][LLM_PLAYER_ID])        fan_ge_2 = float(summary["avg_stats"]["hu_fan_ge_1"][LLM_PLAYER_ID])        dianpao_count = float(summary["avg_stats"]["dianpao_count"][LLM_PLAYER_ID])        total_fan = float(summary["avg_stats"]["total_fan"][LLM_PLAYER_ID])        final_balance = float(summary["avg_final_balances"][LLM_PLAYER_ID])        net = final_balance - initial_balance        hu_rates.append((hu_count / num_episodes) * 100 if num_episodes > 0 else 0.0)        fan_ge_2_counts.append(fan_ge_2)        dianpao_rates.append((dianpao_count / num_episodes) * 100 if num_episodes > 0 else 0.0)        total_fans.append(total_fan)        final_balances.append(final_balance)        net_incomes.append(net)    if INCLUDE_BOT_AVG:        bot_hu_rates = []        bot_fan_ge_2 = []        bot_dianpao_rates = []        bot_total_fans = []        bot_final_balances = []        bot_net_incomes = []        for summary in summaries:            num_episodes = summary["num_episodes"]            initial_balance = summary["initial_balance"]            bot_hu_count = np.mean([float(summary["avg_stats"]["hu_count"][i]) for i in BOT_PLAYER_IDS])            bot_fan_ge_2_count = np.mean([float(summary["avg_stats"]["hu_fan_ge_1"][i]) for i in BOT_PLAYER_IDS])            bot_dianpao_count = np.mean([float(summary["avg_stats"]["dianpao_count"][i]) for i in BOT_PLAYER_IDS])            bot_total_fan = np.mean([float(summary["avg_stats"]["total_fan"][i]) for i in BOT_PLAYER_IDS])            bot_final_balance = np.mean([float(summary["avg_final_balances"][i]) for i in BOT_PLAYER_IDS])            bot_net = bot_final_balance - initial_balance            bot_hu_rates.append((bot_hu_count / num_episodes) * 100 if num_episodes > 0 else 0.0)            bot_fan_ge_2.append(bot_fan_ge_2_count)            bot_dianpao_rates.append((bot_dianpao_count / num_episodes) * 100 if num_episodes > 0 else 0.0)            bot_total_fans.append(bot_total_fan)            bot_final_balances.append(bot_final_balance)            bot_net_incomes.append(bot_net)        labels.append(MODEL_DISPLAY_NAMES["bot-avg"])        colors.append(MODEL_COLORS["bot-avg"])        hatches.append(MODEL_HATCHES["bot-avg"])        hu_rates.append(float(np.mean(bot_hu_rates)))        fan_ge_2_counts.append(float(np.mean(bot_fan_ge_2)))        dianpao_rates.append(float(np.mean(bot_dianpao_rates)))        total_fans.append(float(np.mean(bot_total_fans)))        final_balances.append(float(np.mean(bot_final_balances)))        net_incomes.append(float(np.mean(bot_net_incomes)))    return labels, colors, hatches, hu_rates, fan_ge_2_counts, total_fans, dianpao_rates, final_balances, net_incomesdef add_bar_labels(ax, bars, values, fmt):    y_min, y_max = ax.get_ylim()    y_range = y_max - y_min    offset = y_range * 0.03    for bar, value in zip(bars, values):        if value < 0:            ax.text(                bar.get_x() + bar.get_width() / 2,                value - offset,                fmt.format(value),                ha="center",                va="top",                fontsize=10,                fontweight="bold",            )        else:            ax.text(                bar.get_x() + bar.get_width() / 2,                value + offset,                fmt.format(value),                ha="center",                va="bottom",                fontsize=10,                fontweight="bold",            )def plot_metric_bar_chart(model_tags=None):    if model_tags is None:        model_tags = MODEL_TAGS    configure_matplotlib()    labels, colors, hatches, hu_rates, fan_ge_2_counts, total_fans, dianpao_rates, final_balances, net_incomes = build_metric_data(model_tags)    x = np.arange(len(labels))    # 修改布局：3行2列    fig, axes = plt.subplots(3, 2, figsize=(14, 16))    axes = axes.flatten()    metric_specs = [        ("Win Rate (Hu Rate)", "Rate (%)", hu_rates, "{:.2f}%"),        ("Win Count (>= 2 Fan)", "Count", fan_ge_2_counts, "{:.1f}"),        ("Total Fan", "Fan Count", total_fans, "{:.1f}"),        ("Discard Loss Rate (DianPao)", "Rate (%)", dianpao_rates, "{:.2f}%"),        ("Final Balance", "Score", final_balances, "{:.0f}"),        ("Net Income (Change)", "Score", net_incomes, "{:+.0f}"),    ]    figure_title = "Comprehensive Core Metrics Comparison of Models and Bot Baseline"    for i, (title, ylabel, values, fmt) in enumerate(metric_specs):        ax = axes[i]        bars = ax.bar(x, values, color=colors, width=0.62)                # 为不同模型柱子增加指定的纹理填充        for bar, hatch in zip(bars, hatches):            bar.set_hatch(hatch)            bar.set_edgecolor('black') # 加上黑色边框让纹理更清晰            bar.set_linewidth(0.8)        ax.set_xticks(x)        ax.set_xticklabels(labels, rotation=12)        ax.set_title(title, fontsize=13, fontweight="bold")        ax.set_ylabel(ylabel)        ax.grid(axis="y", alpha=0.3, linestyle="--")        upper = max(values) if values else 0.0        lower = min(values) if values else 0.0        if lower >= 0:            ax.set_ylim(0, upper * 1.18 if upper > 0 else 1.0)        else:            # 对于 Net Income 这种可能出现负数的数据，需要调整轴以包含上下限并绘制0轴            y_max = max(abs(upper), abs(lower)) * 1.25            ax.set_ylim(-y_max, y_max)            ax.axhline(y=0, color="black", linewidth=0.8, alpha=0.6)        add_bar_labels(ax, bars, values, fmt)    fig.suptitle(figure_title, fontsize=17, fontweight="bold")    plt.tight_layout()    os.makedirs(RESULTS_DIR, exist_ok=True)    output_path = os.path.join(RESULTS_DIR, "model_metrics_bar.png")    plt.savefig(output_path, dpi=150, bbox_inches="tight")    plt.close()    print(f"Saved chart to: {output_path}")if __name__ == "__main__":    plot_metric_bar_chart()